    /**
     * @method
     * @name bitmart#watchBidsAsks
     * @see https://developer-pro.bitmart.com/en/spot/#public-ticker-channel
     * @see https://developer-pro.bitmart.com/en/futuresv2/#public-ticker-channel
     * @description watches best bid & ask for symbols
     * @param {string[]} symbols unified symbol of the market to fetch the ticker for
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} a [ticker structure]{@link https://docs.ccxt.com/?id=ticker-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> watchBidsAsks(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object symbols = Helpers.getArg(optionalArgs, 0, null);
            Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
            if (Helpers.isTrue(Helpers.isEqual(this.markets, null)))
            {
                (this.loadMarkets()).join();
            }
            symbols = this.marketSymbols(symbols, null, false);
            if (Helpers.isTrue(Helpers.isEqual(symbols, null)))
            {
                symbols = new java.util.ArrayList<Object>(java.util.Arrays.asList());
            }
            Object firstMarket = this.getMarketFromSymbols(symbols);
            Object marketType = null;
            var marketTypeparametersVariable = this.handleMarketTypeAndParams("watchBidsAsks", firstMarket, parameters);
            marketType = ((java.util.List<Object>) marketTypeparametersVariable).get(0);
            parameters = ((java.util.List<Object>) marketTypeparametersVariable).get(1);
            Object url = this.implodeHostname(Helpers.GetValue(Helpers.GetValue(Helpers.GetValue(Helpers.GetValue(this.urls, "api"), "ws"), marketType), "public"));
            Object channelType = ((Helpers.isTrue((Helpers.isEqual(marketType, "spot"))))) ? "spot/bookTicker" : "futures/ticker";
            Object actionType = ((Helpers.isTrue((Helpers.isEqual(marketType, "spot"))))) ? "op" : "action";
            Object rawSubscriptions = new java.util.ArrayList<Object>(java.util.Arrays.asList());
            Object messageHashes = new java.util.ArrayList<Object>(java.util.Arrays.asList());
            for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(symbols)); i++)
            {
                Object market = this.market(Helpers.GetValue(symbols, i));
                Object rawHash = Helpers.add(Helpers.add(channelType, ":"), Helpers.GetValue(market, "id"));
                Object messageHash = Helpers.add("bidask::", Helpers.GetValue(market, "symbol"));
                ((java.util.List<Object>)messageHashes).add(messageHash);
                if (!Helpers.isTrue(this.subscriptionExistsForHash(url, messageHash)))
                {
                    ((java.util.List<Object>)rawSubscriptions).add(rawHash);
                }
            }
            if (Helpers.isTrue(!Helpers.isEqual(marketType, "spot")))
            {
                rawSubscriptions = new java.util.ArrayList<Object>(java.util.Arrays.asList(channelType));
            }
            final Object finalRawSubscriptions = rawSubscriptions;
            Object request = new java.util.HashMap<String, Object>() {{
                put( "args", finalRawSubscriptions );
            }};
            Helpers.addElementToObject(request, actionType, "subscribe");
            Object newTickers = (this.watchMultiple(url, messageHashes, request, messageHashes, null)).join();
            if (Helpers.isTrue(this.newUpdates))
            {
                Object tickers = new java.util.HashMap<String, Object>() {{}};
                Helpers.addElementToObject(tickers, Helpers.GetValue(newTickers, "symbol"), newTickers);
                return tickers;
            }
            return this.filterByArray(this.bidsasks, "symbol", symbols);
        });

    }

    public void handleBidAsk(Client client, Object message)
    {
        Object table = this.safeString(message, "table");
        Object isSpot = (!Helpers.isEqual(table, null));
        Object rawTickers = new java.util.ArrayList<Object>(java.util.Arrays.asList());
        if (Helpers.isTrue(isSpot))
        {
            rawTickers = this.safeList(message, "data", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
        } else
        {
            rawTickers = new java.util.ArrayList<Object>(java.util.Arrays.asList(this.safeDict(message, "data", new java.util.HashMap<String, Object>() {{}})));
        }
        if (!Helpers.isTrue(Helpers.getArrayLength(rawTickers)))
        {
            return;
        }
        for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(rawTickers)); i++)
        {
            Object ticker = this.parseWsBidAsk(Helpers.GetValue(rawTickers, i));
            Object symbol = Helpers.GetValue(ticker, "symbol");
            if (Helpers.isTrue(!Helpers.isEqual(symbol, null)))
            {
                Helpers.addElementToObject(this.bidsasks, symbol, ticker);
            }
            Object messageHash = Helpers.add("bidask::", symbol);
            client.resolve(ticker, messageHash);
        }
    }

    public Object parseWsBidAsk(Object ticker, Object... optionalArgs)
    {
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object marketId = this.safeString(ticker, "symbol");
        market = this.safeMarket(marketId, market);
        Object symbol = this.safeString(market, "symbol");
        Object timestamp = this.safeInteger(ticker, "ms_t");
        return this.safeTicker(new java.util.HashMap<String, Object>() {{
            put( "symbol", symbol );
            put( "timestamp", timestamp );
            put( "datetime", BitmartCore.this.iso8601(timestamp) );
            put( "ask", BitmartCore.this.safeString2(ticker, "ask_px", "ask_price") );
            put( "askVolume", BitmartCore.this.safeString2(ticker, "ask_sz", "ask_vol") );
            put( "bid", BitmartCore.this.safeString2(ticker, "bid_px", "bid_price") );
            put( "bidVolume", BitmartCore.this.safeString2(ticker, "bid_sz", "bid_vol") );
            put( "info", ticker );
        }}, market);
    }

