    public void handlePositions(Client client, Object message)
    {
        //
        //    {
        //        "group":"futures/position",
        //        "data":[
        //           {
        //              "symbol":"LTCUSDT",
        //              "hold_volume":"5",
        //              "position_type":2,
        //              "open_type":2,
        //              "frozen_volume":"0",
        //              "close_volume":"0",
        //              "hold_avg_price":"71.582",
        //              "close_avg_price":"0",
        //              "open_avg_price":"71.582",
        //              "liquidate_price":"0",
        //              "create_time":1701623327513,
        //              "update_time":1701627620439
        //           },
        //           {
        //              "symbol":"LTCUSDT",
        //              "hold_volume":"6",
        //              "position_type":1,
        //              "open_type":2,
        //              "frozen_volume":"0",
        //              "close_volume":"0",
        //              "hold_avg_price":"71.681666666666666667",
        //              "close_avg_price":"0",
        //              "open_avg_price":"71.681666666666666667",
        //              "liquidate_price":"0",
        //              "create_time":1701621167225,
        //              "update_time":1701628152614
        //           }
        //        ]
        //    }
        //
        Object data = this.safeList(message, "data", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
        if (Helpers.isTrue(Helpers.isEqual(this.positions, null)))
        {
            this.positions = new ArrayCache.ArrayCacheBySymbolBySide();
        }
        Object cache = this.positions;
        Object newPositions = new java.util.ArrayList<Object>(java.util.Arrays.asList());
        for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(data)); i++)
        {
            Object rawPosition = Helpers.GetValue(data, i);
            Object position = this.parseWsPosition(rawPosition);
            ((java.util.List<Object>)newPositions).add(position);
            Helpers.callDynamically(cache, "append", new Object[]{position});
        }
        Object messageHashes = this.findMessageHashes(client, "positions::");
        for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(messageHashes)); i++)
        {
            Object messageHash = Helpers.GetValue(messageHashes, i);
            Object parts = Helpers.split(messageHash, "::");
            Object symbolsString = Helpers.GetValue(parts, 1);
            Object symbols = Helpers.split(symbolsString, ",");
            Object positions = this.filterByArray(newPositions, "symbol", symbols, false);
            if (!Helpers.isTrue(this.isEmpty(positions)))
            {
                client.resolve(positions, messageHash);
            }
        }
        client.resolve(newPositions, "positions");
    }

