    public void handleTrade(Client client, Object message)
    {
        //
        // spot
        //    {
        //        "table": "spot/trade",
        //        "data": [
        //            {
        //                "price": "52700.50",
        //                "s_t": 1630982050,
        //                "side": "buy",
        //                "size": "0.00112",
        //                "symbol": "BTC_USDT"
        //            },
        //        ]
        //    }
        //
        // swap
        //    {
        //        "group":"futures/trade:BTCUSDT",
        //        "data":[
        //           {
        //              "trade_id":6798697637,
        //              "symbol":"BTCUSDT",
        //              "deal_price":"39735.8",
        //              "deal_vol":"2",
        //              "way":1,
        //              "created_at":"2023-12-03T15:48:23.517518538Z",
        //              "m": true,
        //           }
        //        ]
        //    }
        //
        Object data = this.safeList(message, "data");
        if (Helpers.isTrue(Helpers.isEqual(data, null)))
        {
            return;
        }
        Object symbol = null;
        Object length = Helpers.getArrayLength(data);
        Object isSwap = (Helpers.inOp(message, "group"));
        if (Helpers.isTrue(isSwap))
        {
            // in swap, chronologically decreasing: 1709536849322, 1709536848954,
            for (var i = 0; Helpers.isLessThan(i, length); i++)
            {
                Object index = Helpers.subtract(Helpers.subtract(length, i), 1);
                symbol = this.handleTradeLoop(Helpers.GetValue(data, index));
            }
        } else
        {
            // in spot, chronologically increasing: 1709536771200, 1709536771226,
            for (var i = 0; Helpers.isLessThan(i, length); i++)
            {
                symbol = this.handleTradeLoop(Helpers.GetValue(data, i));
            }
        }
        if (Helpers.isTrue(!Helpers.isEqual(symbol, null)))
        {
            client.resolve(Helpers.GetValue(this.trades, symbol), Helpers.add("trade::", symbol));
        }
    }

    public Object handleTradeLoop(Object entry)
    {
        Object trade = this.parseWsTrade(entry);
        Object symbol = Helpers.GetValue(trade, "symbol");
        if (Helpers.isTrue(Helpers.isEqual(symbol, null)))
        {
            return symbol;
        }
        Object tradesLimit = this.safeInteger(this.options, "tradesLimit", 1000);
        if (Helpers.isTrue(Helpers.isEqual(this.safeValue(this.trades, symbol), null)))
        {
            Helpers.addElementToObject(this.trades, symbol, new ArrayCache(((Number)tradesLimit).intValue()));
        }
        Object stored = Helpers.GetValue(this.trades, symbol);
        Helpers.callDynamically(stored, "append", new Object[]{trade});
        return symbol;
    }

    public Object parseWsTrade(Object trade, Object... optionalArgs)
    {
        //
        // spot
        //     {
        //         "ms_t": 1740320841473,
        //         "price": "2806.54",
        //         "s_t": 1740320841,
        //         "side": "sell",
        //         "size": "0.77598",
        //         "symbol": "ETH_USDT"
        //     }
        //
        // swap
        //     {
        //         "trade_id": "3000000245258661",
        //         "symbol": "ETHUSDT",
        //         "deal_price": "2811.1",
        //         "deal_vol": "1858",
        //         "way": 2,
        //         "m": true,
        //         "created_at": "2025-02-23T13:59:59.646490751Z"
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object marketId = this.safeString(trade, "symbol");
        market = this.safeMarket(marketId, market);
        Object timestamp = this.safeInteger(trade, "ms_t");
        Object datetime = null;
        if (Helpers.isTrue(Helpers.isEqual(timestamp, null)))
        {
            datetime = this.safeString(trade, "created_at");
            timestamp = this.parse8601(datetime);
        } else
        {
            datetime = this.iso8601(timestamp);
        }
        Object takerOrMaker = null; // true for public trades
        Object side = this.safeString(trade, "side");
        Object buyerMaker = this.safeBool(trade, "m");
        if (Helpers.isTrue(!Helpers.isEqual(buyerMaker, null)))
        {
            if (Helpers.isTrue(Helpers.isEqual(side, null)))
            {
                if (Helpers.isTrue(buyerMaker))
                {
                    side = "sell";
                } else
                {
                    side = "buy";
                }
            }
            takerOrMaker = "taker";
        }
        final Object finalTimestamp = timestamp;
        final Object finalDatetime = datetime;
        final Object finalMarket = market;
        final Object finalSide = side;
        final Object finalTakerOrMaker = takerOrMaker;
        return this.safeTrade(new java.util.HashMap<String, Object>() {{
            put( "info", trade );
            put( "id", BitmartCore.this.safeString(trade, "trade_id") );
            put( "order", null );
            put( "timestamp", finalTimestamp );
            put( "datetime", finalDatetime );
            put( "symbol", Helpers.GetValue(finalMarket, "symbol") );
            put( "type", null );
            put( "side", finalSide );
            put( "price", BitmartCore.this.safeString2(trade, "price", "deal_price") );
            put( "amount", BitmartCore.this.safeString2(trade, "size", "deal_vol") );
            put( "cost", null );
            put( "takerOrMaker", finalTakerOrMaker );
            put( "fee", null );
        }}, market);
    }

    public void handleTicker(Client client, Object message)
    {
        //
        //    {
        //        "data": [
        //            {
        //                "base_volume_24h": "78615593.81",
        //                "high_24h": "52756.97",
        //                "last_price": "52638.31",
        //                "low_24h": "50991.35",
        //                "open_24h": "51692.03",
        //                "s_t": 1630981727,
        //                "symbol": "BTC_USDT"
        //            }
        //        ],
        //        "table": "spot/ticker"
        //    }
        //
        //     {
        //         "data": {
        //             "symbol": "ETHUSDT",
        //             "last_price": "2807.73",
        //             "volume_24": "2227011952",
        //             "range": "0.0273398194664491",
        //             "mark_price": "2807.5",
        //             "index_price": "2808.71047619",
        //             "ask_price": "2808.04",
        //             "ask_vol": "7371",
        //             "bid_price": "2807.28",
        //             "bid_vol": "3561"
        //         },
        //         "group": "futures/ticker:ETHUSDT@100ms"
        //     }
        //
        this.handleBidAsk(client, message);
        Object table = this.safeString(message, "table");
        Object isSpot = (!Helpers.isEqual(table, null));
        Object rawTickers = new java.util.ArrayList<Object>(java.util.Arrays.asList());
        if (Helpers.isTrue(isSpot))
        {
            rawTickers = this.safeList(message, "data", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
        } else
        {
            rawTickers = new java.util.ArrayList<Object>(java.util.Arrays.asList(this.safeDict(message, "data", new java.util.HashMap<String, Object>() {{}})));
        }
        if (!Helpers.isTrue(Helpers.getArrayLength(rawTickers)))
        {
            return;
        }
        for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(rawTickers)); i++)
        {
            Object ticker = ((Helpers.isTrue(isSpot))) ? this.parseTicker(Helpers.GetValue(rawTickers, i)) : this.parseWsSwapTicker(Helpers.GetValue(rawTickers, i));
            Object symbol = Helpers.GetValue(ticker, "symbol");
            if (Helpers.isTrue(!Helpers.isEqual(symbol, null)))
            {
                Helpers.addElementToObject(this.tickers, symbol, ticker);
            }
            Object messageHash = Helpers.add("ticker::", symbol);
            client.resolve(ticker, messageHash);
        }
    }

