    public void handleFundingRate(Client client, Object message)
    {
        //
        //     {
        //         "data": {
        //             "symbol": "BTCUSDT",
        //             "fundingRate": "0.0000561",
        //             "fundingTime": 1770978448000,
        //             "nextFundingRate": "-0.0000195",
        //             "nextFundingTime": 1770998400000,
        //             "funding_upper_limit": "0.0375",
        //             "funding_lower_limit": "-0.0375",
        //             "ts": 1770978448970
        //         },
        //         "group": "futures/fundingRate:BTCUSDT"
        //     }
        //
        Object data = this.safeDict(message, "data", new java.util.HashMap<String, Object>() {{}});
        Object fundingRate = this.parseFundingRate(data);
        Object symbol = Helpers.GetValue(fundingRate, "symbol");
        if (Helpers.isTrue(!Helpers.isEqual(symbol, null)))
        {
            Helpers.addElementToObject(this.fundingRates, symbol, fundingRate);
        }
        Object messageHash = Helpers.add("fundingRate::", symbol);
        client.resolve(fundingRate, messageHash);
    }

    public java.util.concurrent.CompletableFuture<Object> authenticate(Object type2, Object... optionalArgs)
    {
        final Object type3 = type2;
        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {
            Object type = type3;
            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            this.checkRequiredCredentials();
            Object url = this.implodeHostname(Helpers.GetValue(Helpers.GetValue(Helpers.GetValue(Helpers.GetValue(this.urls, "api"), "ws"), type), "private"));
            Object messageHash = "authenticated";
            Client client = this.client(url);
            io.github.ccxt.ws.Future future = client.reusableFuture((String)messageHash);
            Object authenticated = this.safeValue(client.subscriptions, messageHash);
            if (Helpers.isTrue(Helpers.isEqual(authenticated, null)))
            {
                Object timestamp = String.valueOf(this.milliseconds());
                Object memo = this.uid;
                Object path = "bitmart.WebSocket";
                Object auth = Helpers.add(Helpers.add(Helpers.add(Helpers.add(timestamp, "#"), memo), "#"), path);
                Object signature = this.hmac(this.encode(auth), this.encode(this.secret), sha256());
                Object request = null;
                if (Helpers.isTrue(Helpers.isEqual(type, "spot")))
                {
                    final Object finalTimestamp = timestamp;
                    request = new java.util.HashMap<String, Object>() {{
                        put( "op", "login" );
                        put( "args", new java.util.ArrayList<Object>(java.util.Arrays.asList(BitmartCore.this.apiKey, finalTimestamp, signature)) );
                    }};
                } else
                {
                    final Object finalTimestamp_2 = timestamp;
                    request = new java.util.HashMap<String, Object>() {{
                        put( "action", "access" );
                        put( "args", new java.util.ArrayList<Object>(java.util.Arrays.asList(BitmartCore.this.apiKey, finalTimestamp_2, signature, "web")) );
                    }};
                }
                Object message = this.extend(request, parameters);
                this.watch(url, messageHash, message, messageHash, null);
            }
            return ((io.github.ccxt.ws.Future)future).getFuture().join();
        });

    }

