    public Object handleErrorMessage(Client client, Object message)
    {
        //
        //    { event: "error", message: "Invalid sign", errorCode: 30013 }
        //    {"event":"error","message":"Unrecognized request: {\"event\":\"subscribe\",\"channel\":\"spot/depth:BTC-USDT\"}","errorCode":30039}
        //    {
        //        action: '',
        //        group: 'futures/trade:BTCUSDT',
        //        success: false,
        //        request: { action: '', args: [ 'futures/trade:BTCUSDT' ] },
        //        error: 'Invalid action [] for group [futures/trade:BTCUSDT]'
        //    }
        //
        Object errorCode = this.safeString(message, "errorCode");
        Object error = this.safeString(message, "error");
        // Duplicate-subscription notice errorCode 90008: bitmart's WS rejects
        // a re-subscribe attempt on a topic that's already active on this
        // connection, but the original subscription keeps delivering data —
        // so treat it as benign. Without this short-circuit, the generic
        // client.reject below kills every unrelated in-flight future —
        // e.g. a watchOHLCV waiting on its kline subscription gets rejected
        // by an orderbook 90008 raised on the same socket.
        if (Helpers.isTrue(Helpers.isEqual(errorCode, "90008")))
        {
            return false;
        }
        try
        {
            if (Helpers.isTrue(Helpers.isTrue(!Helpers.isEqual(errorCode, null)) || Helpers.isTrue(!Helpers.isEqual(error, null))))
            {
                Object feedback = Helpers.add(Helpers.add(this.id, " "), this.json(message));
                this.throwExactlyMatchedException(Helpers.GetValue(this.exceptions, "exact"), errorCode, feedback);
                Object messageString = this.safeValue(message, "message", error);
                this.throwBroadlyMatchedException(Helpers.GetValue(this.exceptions, "broad"), messageString, feedback);
                Object action = this.safeString(message, "action");
                if (Helpers.isTrue(Helpers.isEqual(action, "access")))
                {
                    throw new AuthenticationError((String)feedback) ;
                }
                throw new ExchangeError((String)feedback) ;
            }
            return false;
        } catch(Exception e)
        {
            if (Helpers.isTrue((Helpers.isInstance(e, AuthenticationError.class))))
            {
                Object messageHash = "authenticated";
                client.reject(e, messageHash);
                if (Helpers.isTrue(Helpers.inOp(client.subscriptions, messageHash)))
                {
                    ((java.util.Map<String,Object>)client.subscriptions).remove((String)messageHash);
                }
            }
            client.reject(e);
            return true;
        }
    }

    public void handleUnSubscription(Client client, Object message)
    {
        //
        // spot
        //     {
        //         "topic": "spot/ticker:ETH_USDT",
        //         "event": "unsubscribe"
        //     }
        //
        // swap
        //     {
        //         "action": "unsubscribe",
        //         "group": "futures/ticker:ETHUSDT",
        //         "success": true,
        //         "request": {
        //             "action": "unsubscribe",
        //             "args": [
        //                 "futures/ticker:ETHUSDT"
        //             ]
        //         }
        //     }
        //
        Object messageTopic = this.safeString2(message, "topic", "group", "");
        Object unSubMessageTopic = Helpers.add("unsubscribe::", messageTopic);
        // one message includes info about one unsubscription only even if we requested multiple
        // so we can not just create subscription object in unWatch method and use it here
        // we need to reconstruct subscription params from the messageTopic
        Object subscription = this.getUnSubParams(messageTopic);
        Object subHash = this.safeString(subscription, "subHash");
        Object unsubHash = Helpers.add("unsubscribe::", subHash);
        Object subHashIsPrefix = this.safeBool(subscription, "subHashIsPrefix", false);
        // clean up both ways of storing subscription and unsubscription
        this.cleanUnsubscription(client, ((String)subHash), unsubHash, subHashIsPrefix);
        this.cleanUnsubscription(client, messageTopic, unSubMessageTopic, subHashIsPrefix);
        this.cleanCache(subscription);
    }

    public Object getUnSubParams(Object messageTopic)
    {
        Object parts = Helpers.split(messageTopic, ":");
        Object channel = this.safeString(parts, 0, "");
        Object marketTypeAndTopic = Helpers.split(channel, "/");
        Object rawMarketType = this.safeStringLower(marketTypeAndTopic, 0);
        Object marketType = this.parseMarketType(((String)rawMarketType));
        Object topic = this.safeString(marketTypeAndTopic, 1, "");
        Object thirdPart = this.safeString(marketTypeAndTopic, 2);
        if (Helpers.isTrue(!Helpers.isEqual(thirdPart, null)))
        {
            topic = Helpers.add(topic, Helpers.add("/", thirdPart));
        }
        Object marketId = this.safeString(parts, 1);
        Object symbols = new java.util.ArrayList<Object>(java.util.Arrays.asList());
        Object symbol = null;
        Object subHash = topic;
        Object hashDelimiter = ":";
        Object subHashIsPrefix = false;
        Object parsedTopic = this.parseTopic(topic);
        if (Helpers.isTrue(Helpers.isTrue((Helpers.isEqual(parsedTopic, "orders"))) || Helpers.isTrue((Helpers.isEqual(parsedTopic, "positions")))))
        {
            subHash = parsedTopic;
            hashDelimiter = "::";
        }
        if (Helpers.isTrue(Helpers.isTrue((!Helpers.isEqual(marketId, null))) && Helpers.isTrue((!Helpers.isEqual(marketId, "ALL_SYMBOLS")))))
        {
            // if marketId is defined, we have a single symbol subscription
            Object delimiter = ((Helpers.isTrue((Helpers.isEqual(marketType, "spot"))))) ? "_" : "";
            Object market = this.safeMarket(marketId, null, delimiter, marketType);
            symbol = Helpers.GetValue(market, "symbol");
            subHash = Helpers.add(subHash, Helpers.add(hashDelimiter, symbol));
            ((java.util.List<Object>)symbols).add(symbol);
        } else
        {
            subHashIsPrefix = true; // need to clean all subHashes with this prefix
        }
        Object symbolsAndTimeframes = new java.util.ArrayList<Object>(java.util.Arrays.asList());
        if (Helpers.isTrue(((String)topic).startsWith(((String)"kline"))))
        {
            Object interval = Helpers.replace((String)topic, (String)"kline", (String)"");
            if (Helpers.isTrue(((String)interval).startsWith(((String)"Bin"))))
            {
                // swap market
                interval = Helpers.replace((String)interval, (String)"Bin", (String)"");
            }
            Object timeframes = this.safeDict(this.options, "timeframes", new java.util.HashMap<String, Object>() {{}});
            Object timeframe = this.findTimeframe(interval, timeframes);
            Object symbolAndTimeframe = new java.util.ArrayList<Object>(java.util.Arrays.asList(symbol, timeframe));
            ((java.util.List<Object>)symbolsAndTimeframes).add(symbolAndTimeframe);
        }
        final Object finalParsedTopic = parsedTopic;
        final Object finalSubHash = subHash;
        final Object finalSubHashIsPrefix = subHashIsPrefix;
        Object result = new java.util.HashMap<String, Object>() {{
            put( "topic", finalParsedTopic );
            put( "symbols", symbols );
            put( "subHash", finalSubHash );
            put( "symbolsAndTimeframes", symbolsAndTimeframes );
            put( "subHashIsPrefix", finalSubHashIsPrefix );
        }};
        return result;
    }

    public Object parseTopic(Object topic)
    {
        if (Helpers.isTrue(((String)topic).startsWith(((String)"depth"))))
        {
            return "orderbook";
        }
        if (Helpers.isTrue(((String)topic).startsWith(((String)"kline"))))
        {
            return "ohlcv";
        }
        Object topics = new java.util.HashMap<String, Object>() {{
            put( "ticker", "ticker" );
            put( "trade", "trades" );
            put( "user/order", "orders" );
            put( "user/orders", "orders" );
            put( "order", "orders" );
            put( "position", "positions" );
        }};
        return this.safeString(topics, topic, topic);
    }

    public Object parseMarketType(Object marketType)
    {
        Object types = new java.util.HashMap<String, Object>() {{
            put( "spot", "spot" );
            put( "futures", "swap" );
        }};
        return this.safeString(types, marketType, marketType);
    }

    public Object subscriptionExistsForHash(Object url, Object hash)
    {
        Client client = this.client(url);
        return (Helpers.inOp(client.subscriptions, hash));
    }

    public void handleMessage(Client client, Object message)
    {
        if (Helpers.isTrue(this.handleErrorMessage(client, message)))
        {
            return;
        }
        //
        //     {"event":"error","message":"Unrecognized request: {\"event\":\"subscribe\",\"channel\":\"spot/depth:BTC-USDT\"}","errorCode":30039}
        //
        // subscribe events on spot:
        //
        //     {"event":"subscribe", "topic":"spot/kline1m:BTC_USDT" }
        //
        // subscribe on contracts:
        //
        //     {"action":"subscribe", "group":"futures/klineBin1m:BTCUSDT", "success":true, "request":{"action":"subscribe", "args":[ "futures/klineBin1m:BTCUSDT" ] } }
        //
        // regular updates - spot
        //
        //     {
        //         "table": "spot/depth",
        //         "action": "partial",
        //         "data": [
        //             {
        //                 "instrument_id":   "BTC-USDT",
        //                 "asks": [
        //                     ["5301.8", "0.03763319", "1"],
        //                     ["5302.4", "0.00305", "2"],
        //                 ],
        //                 "bids": [
        //                     ["5301.7", "0.58911427", "6"],
        //                     ["5301.6", "0.01222922", "4"],
        //                 ],
        //                 "timestamp": "2020-03-16T03:25:00.440Z",
        //                 "checksum": -2088736623
        //             }
        //         ]
        //     }
        //
        // regular updates - contracts
        //
        //     {
        //         group: "futures/klineBin1m:BTCUSDT",
        //         data: {
        //           symbol: "BTCUSDT",
        //           items: [ { o: "67944.7", "h": .... } ],
        //         },
        //       }
        //
        //     { data: '', table: "spot/user/order" }
        //
        // the only realiable way (for both spot & swap) is to check 'data' key
        Object isDataUpdate = (Helpers.inOp(message, "data"));
        if (!Helpers.isTrue(isDataUpdate))
        {
            Object eventVar = this.safeString2(message, "event", "action");
            if (Helpers.isTrue(!Helpers.isEqual(eventVar, null)))
            {
                Object methods = new java.util.HashMap<String, Object>() {{
                    put( "login", "handleAuthenticate");
                    put( "access", "handleAuthenticate");
                    put( "subscribe", "handleSubscriptionStatus");
                    put( "unsubscribe", "handleUnSubscription");
                }};
                Object method = this.safeValue(methods, eventVar);
                if (Helpers.isTrue(!Helpers.isEqual(method, null)))
                {
                    Helpers.callDynamically(this, method, new Object[] {client, message});
                }
            }
        } else
        {
            Object channel = this.safeString2(message, "table", "group", "");
            Object methods = new java.util.HashMap<String, Object>() {{
                put( "depth", "handleOrderBook");
                put( "bookTicker", "handleBidAsk");
                put( "ticker", "handleTicker");
                put( "trade", "handleTrade");
                put( "kline", "handleOHLCV");
                put( "order", "handleOrders");
                put( "position", "handlePositions");
                put( "balance", "handleBalance");
                put( "asset", "handleBalance");
            }};
            if (Helpers.isTrue(Helpers.isGreaterThanOrEqual(Helpers.getIndexOf(channel, "fundingRate"), 0)))
            {
                this.handleFundingRate(client, message);
                return;
            }
            // 'ticker' is a substring of 'bookTicker', so a bookTicker channel could
            // be wrongly captured by (or double-dispatched with) the 'ticker' key in a
            // first-match loop (in Go map iteration order is randomized). Check the
            // bookTicker prefix explicitly, then fall back to a simple first-match.
            if (Helpers.isTrue(Helpers.isGreaterThanOrEqual(Helpers.getIndexOf(channel, "bookTicker"), 0)))
            {
                this.handleBidAsk(client, message);
                return;
            }
            Object keys = Helpers.objectKeys(methods);
            for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(keys)); i++)
            {
                Object key = Helpers.GetValue(keys, i);
                if (Helpers.isTrue(Helpers.isGreaterThanOrEqual(Helpers.getIndexOf(channel, key), 0)))
                {
                    Object method = this.safeValue(methods, key);
                    Helpers.callDynamically(this, method, new Object[] {client, message});
                    return;
                }
            }
        }
    }
